import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"15. オーナーダッシュボード","description":"","frontmatter":{},"headers":[],"relativePath":"tenant/15-owner.md","filePath":"tenant/15-owner.md"}'),h={name:"tenant/15-owner.md"};function l(o,t,i,n,b,s){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_15-オーナーダッシュボード" tabindex="-1">15. オーナーダッシュボード <a class="header-anchor" href="#_15-オーナーダッシュボード" aria-label="Permalink to &quot;15. オーナーダッシュボード&quot;">​</a></h1><p>オーナーロールでログインすると、オーナーダッシュボード（<code>owner-dashboard.html</code>）に自動遷移します。テナント全体の管理を行うための画面です。</p><h2 id="_15-1-タブ一覧" tabindex="-1">15.1 タブ一覧 <a class="header-anchor" href="#_15-1-タブ一覧" aria-label="Permalink to &quot;15.1 タブ一覧&quot;">​</a></h2><table tabindex="0"><thead><tr><th>タブ名</th><th>説明</th></tr></thead><tbody><tr><td>クロス店舗レポート</td><td>全店舗の売上を横並びで比較</td></tr><tr><td>ABC分析</td><td>売上貢献度によるメニュー分類</td></tr><tr><td>店舗管理</td><td>店舗の追加・編集・削除</td></tr><tr><td>ユーザー管理</td><td>全店舗のアカウント管理</td></tr><tr><td>AIアシスタント</td><td>店舗を選択してAI分析</td></tr><tr><td>契約・プラン</td><td>サブスクリプション管理</td></tr><tr><td>決済設定</td><td>Stripe Connect / Square設定</td></tr><tr><td>シフト概況</td><td>全店舗のシフト概要（enterpriseプラン）</td></tr><tr><td>外部POS連携</td><td>スマレジ連携</td></tr></tbody></table><hr><h2 id="_15-2-クロス店舗レポート" tabindex="-1">15.2 クロス店舗レポート <a class="header-anchor" href="#_15-2-クロス店舗レポート" aria-label="Permalink to &quot;15.2 クロス店舗レポート&quot;">​</a></h2><p>全店舗の売上データを横断的に分析します。</p><h3 id="サマリーカード" tabindex="-1">サマリーカード <a class="header-anchor" href="#サマリーカード" aria-label="Permalink to &quot;サマリーカード&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>説明</th></tr></thead><tbody><tr><td>総売上</td><td>全店舗合計</td></tr><tr><td>総注文数</td><td>全店舗合計</td></tr><tr><td>店舗数</td><td>対象店舗数</td></tr><tr><td>平均注文額</td><td>全店舗の平均</td></tr><tr><td>キャンセル件数</td><td>全店舗合計</td></tr></tbody></table><h3 id="店舗別パフォーマンス" tabindex="-1">店舗別パフォーマンス <a class="header-anchor" href="#店舗別パフォーマンス" aria-label="Permalink to &quot;店舗別パフォーマンス&quot;">​</a></h3><p>各店舗の売上・注文数をバーチャートで比較表示します。</p><h3 id="その他の分析" tabindex="-1">その他の分析 <a class="header-anchor" href="#その他の分析" aria-label="Permalink to &quot;その他の分析&quot;">​</a></h3><table tabindex="0"><thead><tr><th>分析項目</th><th>説明</th></tr></thead><tbody><tr><td>サービス時間分析</td><td>平均待ち時間・調理時間・提供時間</td></tr><tr><td>品目ランキング</td><td>全店舗横断でのトップ品目</td></tr><tr><td>キャンセル品目</td><td>キャンセルが多い品目と逸失売上</td></tr><tr><td>迷い品目</td><td>カートに追加されたが削除された品目（メニュー改善のヒント）</td></tr></tbody></table><h3 id="店舗フィルター" tabindex="-1">店舗フィルター <a class="header-anchor" href="#店舗フィルター" aria-label="Permalink to &quot;店舗フィルター&quot;">​</a></h3><p>オーナーは特定の店舗を選択して、その店舗だけのデータを表示することもできます。</p><hr><h2 id="_15-3-abc分析" tabindex="-1">15.3 ABC分析 <a class="header-anchor" href="#_15-3-abc分析" aria-label="Permalink to &quot;15.3 ABC分析&quot;">​</a></h2><p>メニューを売上貢献度でA・B・Cの3ランクに分類します。</p><h3 id="サマリーカード-6項目" tabindex="-1">サマリーカード（6項目） <a class="header-anchor" href="#サマリーカード-6項目" aria-label="Permalink to &quot;サマリーカード（6項目）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>説明</th></tr></thead><tbody><tr><td>総売上</td><td>—</td></tr><tr><td>粗利益</td><td>売上 − 原価</td></tr><tr><td>平均注文額</td><td>—</td></tr><tr><td>注文件数</td><td>—</td></tr><tr><td>品目数</td><td>分析対象の品目数</td></tr><tr><td>総原価</td><td>—</td></tr></tbody></table><h3 id="ランク別サマリー" tabindex="-1">ランク別サマリー <a class="header-anchor" href="#ランク別サマリー" aria-label="Permalink to &quot;ランク別サマリー&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ランク</th><th>基準</th><th>意味</th></tr></thead><tbody><tr><td>A</td><td>売上構成比の上位70%</td><td>主力商品。維持・強化すべき</td></tr><tr><td>B</td><td>売上構成比の70〜90%</td><td>準主力。改善の余地あり</td></tr><tr><td>C</td><td>売上構成比の下位10%</td><td>低貢献。見直しまたは廃止を検討</td></tr></tbody></table><h3 id="abc一覧テーブル" tabindex="-1">ABC一覧テーブル <a class="header-anchor" href="#abc一覧テーブル" aria-label="Permalink to &quot;ABC一覧テーブル&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>ランクバッジ</td><td>A/B/C</td></tr><tr><td>順位</td><td>売上順</td></tr><tr><td>品名</td><td>—</td></tr><tr><td>カテゴリ</td><td>—</td></tr><tr><td>数量</td><td>販売数</td></tr><tr><td>売上</td><td>—</td></tr><tr><td>構成比</td><td>全体に占める割合</td></tr><tr><td>累積構成比</td><td>—</td></tr><tr><td>原価</td><td>—</td></tr><tr><td>利益</td><td>売上 − 原価</td></tr><tr><td>利益率</td><td>—</td></tr></tbody></table><p>CSSのみのバーチャートで視覚化されます（外部チャートライブラリ不使用）。</p><h3 id="カテゴリ別集計" tabindex="-1">カテゴリ別集計 <a class="header-anchor" href="#カテゴリ別集計" aria-label="Permalink to &quot;カテゴリ別集計&quot;">​</a></h3><p>カテゴリ単位でグリッド表示し、カテゴリごとのパフォーマンスを比較します。</p><hr><h2 id="_15-4-店舗管理" tabindex="-1">15.4 店舗管理 <a class="header-anchor" href="#_15-4-店舗管理" aria-label="Permalink to &quot;15.4 店舗管理&quot;">​</a></h2><p>テナント内の店舗を管理します。</p><h3 id="店舗の追加" tabindex="-1">店舗の追加 <a class="header-anchor" href="#店舗の追加" aria-label="Permalink to &quot;店舗の追加&quot;">​</a></h3><table tabindex="0"><thead><tr><th>フィールド</th><th>種類</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td>店舗名</td><td>テキスト</td><td>✅</td><td>日本語名</td></tr><tr><td>店舗名（英語）</td><td>テキスト</td><td>—</td><td>英語名</td></tr><tr><td>スラッグ</td><td>テキスト</td><td>✅</td><td>URL用の識別子。英小文字・数字・ハイフンのみ</td></tr></tbody></table><h3 id="店舗の編集" tabindex="-1">店舗の編集 <a class="header-anchor" href="#店舗の編集" aria-label="Permalink to &quot;店舗の編集&quot;">​</a></h3><ul><li>店舗名の変更</li><li>有効/無効の切替（無効にすると店舗の全機能が停止します）</li></ul><h3 id="店舗の削除" tabindex="-1">店舗の削除 <a class="header-anchor" href="#店舗の削除" aria-label="Permalink to &quot;店舗の削除&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">注意</p><p>店舗を削除すると、その店舗に紐づく全てのデータ（メニュー、注文、シフト等）が影響を受けます。通常は削除ではなく無効化を推奨します。</p></div><hr><h2 id="_15-5-ユーザー管理" tabindex="-1">15.5 ユーザー管理 <a class="header-anchor" href="#_15-5-ユーザー管理" aria-label="Permalink to &quot;15.5 ユーザー管理&quot;">​</a></h2><p>テナント内の全ユーザーアカウントを管理します。</p><h3 id="ユーザーの作成" tabindex="-1">ユーザーの作成 <a class="header-anchor" href="#ユーザーの作成" aria-label="Permalink to &quot;ユーザーの作成&quot;">​</a></h3><table tabindex="0"><thead><tr><th>フィールド</th><th>種類</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td>表示名</td><td>テキスト</td><td>✅</td><td>スタッフの表示名</td></tr><tr><td>ユーザー名</td><td>テキスト</td><td>✅</td><td>ログインID</td></tr><tr><td>メール</td><td>テキスト</td><td>—</td><td>任意</td></tr><tr><td>パスワード</td><td>パスワード</td><td>✅</td><td>初期パスワード</td></tr><tr><td>ロール</td><td>セレクト</td><td>✅</td><td>owner / manager / staff</td></tr><tr><td>所属店舗</td><td>チェックボックス</td><td>✅</td><td>複数店舗を選択可能（ownerは全店舗に暗黙アクセス）</td></tr></tbody></table><h3 id="スタッフ別の表示ツール設定" tabindex="-1">スタッフ別の表示ツール設定 <a class="header-anchor" href="#スタッフ別の表示ツール設定" aria-label="Permalink to &quot;スタッフ別の表示ツール設定&quot;">​</a></h3><p>各スタッフに対して、利用可能な画面（ツール）を店舗ごとに設定できます。</p><table tabindex="0"><thead><tr><th>ツール</th><th>説明</th></tr></thead><tbody><tr><td>handy</td><td>ハンディPOS画面</td></tr><tr><td>kds</td><td>KDS画面</td></tr><tr><td>register</td><td>POSレジ画面</td></tr></tbody></table><h3 id="スタッフ別の時給設定" tabindex="-1">スタッフ別の時給設定 <a class="header-anchor" href="#スタッフ別の時給設定" aria-label="Permalink to &quot;スタッフ別の時給設定&quot;">​</a></h3><p>スタッフごと・店舗ごとに個別の時給を設定できます。未設定の場合はシフト設定のデフォルト時給が使用されます。</p><h3 id="パスワード変更" tabindex="-1">パスワード変更 <a class="header-anchor" href="#パスワード変更" aria-label="Permalink to &quot;パスワード変更&quot;">​</a></h3><p>オーナーは全ユーザーのパスワードを変更できます。</p><ol><li>ユーザー一覧で対象ユーザーの「編集」ボタンをクリック</li><li>「パスワード」欄に新しいパスワードを入力</li><li>「保存」をクリック</li><li>新しいパスワードをスタッフに口頭で伝える</li></ol><hr><h2 id="_15-6-決済設定" tabindex="-1">15.6 決済設定 <a class="header-anchor" href="#_15-6-決済設定" aria-label="Permalink to &quot;15.6 決済設定&quot;">​</a></h2><p>Stripe ConnectやSquareの決済ゲートウェイを設定します（proプラン以上）。</p><h3 id="設定内容" tabindex="-1">設定内容 <a class="header-anchor" href="#設定内容" aria-label="Permalink to &quot;設定内容&quot;">​</a></h3><ul><li>Stripe Connect：接続状態の確認、アカウント連携</li><li>Square：APIキーの設定</li><li>各店舗のオンライン決済有効/無効</li></ul><hr><h2 id="_15-7-シフト概況-enterpriseプラン" tabindex="-1">15.7 シフト概況（enterpriseプラン） <a class="header-anchor" href="#_15-7-シフト概況-enterpriseプラン" aria-label="Permalink to &quot;15.7 シフト概況（enterpriseプラン）&quot;">​</a></h2><p>全店舗のシフト状況を横断的に確認します。</p><h3 id="操作" tabindex="-1">操作 <a class="header-anchor" href="#操作" aria-label="Permalink to &quot;操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>説明</th></tr></thead><tbody><tr><td>店舗セレクター</td><td>特定の店舗を選択</td></tr><tr><td>期間選択</td><td>週次 / 月次</td></tr><tr><td>日付入力</td><td>カスタム期間</td></tr></tbody></table><hr><h2 id="_15-8-外部pos連携-スマレジ" tabindex="-1">15.8 外部POS連携（スマレジ） <a class="header-anchor" href="#_15-8-外部pos連携-スマレジ" aria-label="Permalink to &quot;15.8 外部POS連携（スマレジ）&quot;">​</a></h2><p>スマレジとの連携機能です。</p><h3 id="連携機能" tabindex="-1">連携機能 <a class="header-anchor" href="#連携機能" aria-label="Permalink to &quot;連携機能&quot;">​</a></h3><table tabindex="0"><thead><tr><th>機能</th><th>説明</th></tr></thead><tbody><tr><td>接続状態</td><td>スマレジとのOAuth接続状態を表示</td></tr><tr><td>店舗マッピング</td><td>POSLAの店舗とスマレジの店舗を紐づけ</td></tr><tr><td>メニューインポート</td><td>スマレジの商品をPOSLAにインポート（非破壊。既存メニューは維持されます）</td></tr></tbody></table>',64)])])}const q=d(h,[["render",l]]);export{u as __pageData,q as default};
